//! Tests for `TrustedIssuerStore` — CA-issuer-based client certificate authentication.
//!
//! # Oracle rationale
//!
//! All test vectors were generated by two independent openssl invocations and
//! cross-verified against each other.  No implementation code is used as its
//! own oracle.
//!
//! ## CA + leaf cert generation
//!
//! ```text
//! # Trusted CA
//! openssl req -x509 -newkey ed25519 -keyout /tmp/ti/ca_key.pem \
//!   -out /tmp/ti/ca_cert.pem -days 3650 -nodes -subj "/CN=Test CA"
//!
//! # Leaf cert for "alice" signed by trusted CA
//! openssl req -newkey ed25519 -keyout /tmp/ti/leaf_alice_key.pem \
//!   -out /tmp/ti/leaf_alice_csr.pem -nodes -subj "/CN=alice"
//! openssl x509 -req -in /tmp/ti/leaf_alice_csr.pem \
//!   -CA /tmp/ti/ca_cert.pem -CAkey /tmp/ti/ca_key.pem \
//!   -out /tmp/ti/leaf_alice_cert.pem -days 365
//!
//! # Untrusted CA and its leaf cert
//! openssl req -x509 -newkey ed25519 -keyout /tmp/ti/uca_key.pem \
//!   -out /tmp/ti/uca_cert.pem -days 3650 -nodes -subj "/CN=Untrusted CA"
//! openssl req -newkey ed25519 -keyout /tmp/ti/leaf_bad_key.pem \
//!   -out /tmp/ti/leaf_bad_csr.pem -nodes -subj "/CN=alice"
//! openssl x509 -req -in /tmp/ti/leaf_bad_csr.pem \
//!   -CA /tmp/ti/uca_cert.pem -CAkey /tmp/ti/uca_key.pem \
//!   -out /tmp/ti/leaf_bad_cert.pem -days 365
//!
//! # Self-signed leaf cert (no CA)
//! openssl req -x509 -newkey ed25519 -keyout /tmp/ti/self_key.pem \
//!   -out /tmp/ti/self_cert.pem -days 365 -nodes -subj "/CN=alice"
//!
//! # Convert all to DER
//! for f in ca_cert leaf_alice_cert uca_cert leaf_bad_cert self_cert; do
//!   openssl x509 -in /tmp/ti/${f}.pem -outform DER -out /tmp/ti/${f}.der
//! done
//! ```
//!
//! ## Chain verification (openssl oracle confirms correct CA relationships)
//!
//! ```text
//! openssl verify -CAfile /tmp/ti/ca_cert.pem /tmp/ti/leaf_alice_cert.pem
//! → leaf_alice_cert.pem: OK
//!
//! openssl verify -CAfile /tmp/ti/ca_cert.pem /tmp/ti/leaf_bad_cert.pem
//! → error 20: unable to get local issuer certificate   (EXPECTED FAILURE)
//! ```

use usenet_ipfs_auth::{TrustedIssuerEntry, TrustedIssuerStore};

// ---------------------------------------------------------------------------
// Test fixtures: DER-encoded certificates
//
// All generated by openssl as documented above.  Verified by openssl chain
// verification.  These bytes are the authoritative external-oracle input.
// ---------------------------------------------------------------------------

