/// Minimal Base64 encoding using the standard alphabet.
fn base64_encode(bytes: &[u8]) -> String {
    const ALPHABET: &[u8] = b"ABCDEFGHIJKLMNOPQRSTUVWXYZabcdefghijklmnopqrstuvwxyz0123456789+/";
    let mut out = String::new();
    for chunk in bytes.chunks(3) {
        let b0 = chunk[0] as usize;
        let b1 = if chunk.len() > 1 {
            chunk[1] as usize
        } else {
            0
        };
        let b2 = if chunk.len() > 2 {
            chunk[2] as usize
        } else {
            0
        };
        out.push(ALPHABET[b0 >> 2] as char);
        out.push(ALPHABET[((b0 & 3) << 4) | (b1 >> 4)] as char);
        if chunk.len() > 1 {
            out.push(ALPHABET[((b1 & 0xf) << 2) | (b2 >> 6)] as char);
        } else {
            out.push('=');
        }
        if chunk.len() > 2 {
            out.push(ALPHABET[b2 & 0x3f] as char);
        } else {
            out.push('=');
        }
    }
    out
}

/// Write any DER-encoded CA cert to a temp file as PEM; return the temp file
/// handle (must stay alive) and the path.
fn ca_der_to_pem_file(ca_der: &[u8]) -> (tempfile::NamedTempFile, std::path::PathBuf) {
    use std::io::Write as _;
    let tmp = tempfile::NamedTempFile::new().expect("tempfile");
    let b64 = base64_encode(ca_der);
    let pem = format!(
        "-----BEGIN CERTIFICATE-----\n{}\n-----END CERTIFICATE-----\n",
        b64.as_bytes()
            .chunks(64)
            .map(|c| std::str::from_utf8(c).unwrap())
            .collect::<Vec<_>>()
            .join("\n")
    );
    let path = tmp.path().to_path_buf();
    tmp.as_file().write_all(pem.as_bytes()).expect("write PEM");
    (tmp, path)
}

/// Build a TrustedIssuerStore configured with the trusted CA via cert_path.
fn store_with_trusted_ca_cert_path() -> TrustedIssuerStore {
    let (tmp, path) = ca_der_to_pem_file(CA_CERT_DER);
    let entry = TrustedIssuerEntry {
        cert_path: path.to_string_lossy().into_owned(),
    };
    let store = TrustedIssuerStore::from_config(&[entry])
        .expect("from_config with valid CA cert must succeed");
    drop(tmp);
    store
}

// ---------------------------------------------------------------------------
// Test 1: valid CA-signed leaf cert → CN returned
//
// Security invariant: a cert properly signed by the configured CA is
// authenticated; the returned value is the leaf CN exactly.
// ---------------------------------------------------------------------------

#[test]
fn valid_ca_signed_leaf_returns_cn() {
    let store = store_with_trusted_ca_cert_path();
    let result = store.verify_and_extract_cn(LEAF_ALICE_DER);
    assert!(
        result.is_ok(),
        "verify_and_extract_cn must not error on a valid CA-signed cert: {:?}",
        result.err()
    );
    let cn = result.unwrap();
    assert_eq!(
        cn.as_deref(),
        Some("alice"),
        "leaf CN must be 'alice'; got {:?}",
        cn
    );
}

// ---------------------------------------------------------------------------
// Test 2: self-signed cert → None (not issued by any trusted CA)
//
// Security invariant: a cert whose issuer is not in the trusted_issuers list
// must NOT authenticate, even if the CN is valid.
// ---------------------------------------------------------------------------

#[test]
fn self_signed_cert_not_authenticated() {
    let store = store_with_trusted_ca_cert_path();
    let result = store.verify_and_extract_cn(SELF_SIGNED_ALICE_DER);
    assert!(
        result.is_ok(),
        "verify_and_extract_cn must not error on a parseable self-signed cert: {:?}",
        result.err()
    );
    assert_eq!(
        result.unwrap(),
        None,
        "self-signed cert must not be authenticated (not issued by any configured CA)"
    );
}

// ---------------------------------------------------------------------------
// Test 3: cert from an untrusted CA → None
//
// Security invariant: a cert signed by an unknown CA must NOT authenticate,
// even if the leaf subject and format are valid.
// The openssl oracle confirms the bad chain: verify returns error 20.
// ---------------------------------------------------------------------------

#[test]
fn cert_from_untrusted_ca_not_authenticated() {
    let store = store_with_trusted_ca_cert_path();
    let result = store.verify_and_extract_cn(LEAF_FROM_UNTRUSTED_CA_DER);
    assert!(
        result.is_ok(),
        "verify_and_extract_cn must not error on a parseable untrusted-CA cert: {:?}",
        result.err()
    );
    assert_eq!(
        result.unwrap(),
        None,
        "cert from untrusted CA must not be authenticated"
    );
}

// ---------------------------------------------------------------------------
// Test 4: forged signature (one bit flipped) → None
//
// Security invariant: the signature field is cryptographically checked; a
// trivial mutation of the signature bytes must be detected and rejected.
//
// We take the valid alice DER and flip bit 0 of the first signature byte
// (byte index 156 in the 223-byte leaf cert — immediately after the 03 41 00
// preamble that precedes the 64-byte ed25519 signature).
// ---------------------------------------------------------------------------

#[test]
fn forged_signature_not_authenticated() {
    // Locate the signature in the DER.
    // ed25519 signature is the last 64 bytes of LEAF_ALICE_DER.
    // The DER ends with: ... 03 41 00 <64 sig bytes>.
    // We flip the first byte of the signature.
    let mut forged = LEAF_ALICE_DER.to_vec();
    let sig_start = forged.len() - 64;
    forged[sig_start] ^= 0x01; // flip the LSB of the first signature byte

    let store = store_with_trusted_ca_cert_path();
    let result = store.verify_and_extract_cn(&forged);
    // The implementation may return Ok(None) or Err — both are acceptable
    // as long as the cert is NOT authenticated as "alice".
    let authenticated = match result {
        Ok(Some(ref cn)) => cn == "alice",
        Ok(None) => false,
        Err(_) => false,
    };
    assert!(
        !authenticated,
        "cert with forged signature must not authenticate as 'alice'"
    );
}

// ---------------------------------------------------------------------------
// Test 5: empty trusted_issuers list → None for any cert
//
// Security invariant: when no CAs are configured, no cert can authenticate
// via issuer chain — regardless of how valid the cert is.
// ---------------------------------------------------------------------------

#[test]
fn empty_issuer_store_authenticates_nothing() {
    let store = TrustedIssuerStore::empty();
    let result = store.verify_and_extract_cn(LEAF_ALICE_DER);
    assert!(
        result.is_ok(),
        "verify_and_extract_cn on empty store must not error: {:?}",
        result.err()
    );
    assert_eq!(
        result.unwrap(),
        None,
        "empty TrustedIssuerStore must return None for any cert"
    );
}

// ---------------------------------------------------------------------------
// Test 6: CN mismatch guard — the store returns the leaf CN; the caller is
// responsible for comparing it to the AUTHINFO USER value.  This test
// confirms the CN returned for alice's cert is exactly "alice", not "bob".
//
// This test documents the contract: the store returns the raw CN; the caller
// (NNTP session layer) must reject auth if CN != requested username.
// A misconfigured session layer that skips this check would be a bug there,
// not in TrustedIssuerStore.
// ---------------------------------------------------------------------------

#[test]
fn returned_cn_is_exact_leaf_cn_not_caller_supplied_name() {
    let store = store_with_trusted_ca_cert_path();
    let cn = store
        .verify_and_extract_cn(LEAF_ALICE_DER)
        .expect("must not error")
        .expect("alice cert must be authenticated");

    assert_eq!(cn, "alice", "returned CN must be exactly 'alice'");
    assert_ne!(cn, "bob", "returned CN must not be 'bob' for alice's cert");

    // The caller's responsibility: compare returned CN to the username being
    // authenticated.  Simulating the session-layer check:
    let authinfo_user = "bob";
    let authenticated_as_bob = cn.eq_ignore_ascii_case(authinfo_user);
    assert!(
        !authenticated_as_bob,
        "alice's cert must not pass authentication when AUTHINFO USER is 'bob'"
    );
}

// ---------------------------------------------------------------------------
// Test 7: malformed DER is rejected gracefully (Err or Ok(None), not panic)
//
// Security invariant: attacker-controlled cert bytes must not crash the server.
// ---------------------------------------------------------------------------

#[test]
fn malformed_der_does_not_panic() {
    let store = store_with_trusted_ca_cert_path();
    let garbage: &[u8] = b"\x30\x82\xff\xff garbage bytes that are not valid DER";
    let result = store.verify_and_extract_cn(garbage);
    // Either Err or Ok(None) is acceptable; panic is not.
    // We assert the invariant: malformed input must not authenticate.
    let authenticated = matches!(result, Ok(Some(_)));
    assert!(
        !authenticated,
        "malformed DER bytes must not result in successful authentication"
    );
}

// ---------------------------------------------------------------------------
// Test 8: empty DER input → not authenticated
// ---------------------------------------------------------------------------

#[test]
fn empty_der_does_not_panic() {
    let store = store_with_trusted_ca_cert_path();
    let result = store.verify_and_extract_cn(&[]);
    let authenticated = matches!(result, Ok(Some(_)));
    assert!(
        !authenticated,
        "empty DER input must not result in successful authentication"
    );
}

// ---------------------------------------------------------------------------
// Test 9: from_config with nonexistent cert_path returns Err
//
// The operator has misconfigured a cert_path that doesn't exist.  The store
// must fail fast at config load time, not silently accept all certs.
// ---------------------------------------------------------------------------

#[test]
fn from_config_with_missing_cert_path_returns_err() {
    let entry = TrustedIssuerEntry {
        cert_path: "/nonexistent/path/__trusted_issuer_test_ca.pem".to_string(),
    };
    let result = TrustedIssuerStore::from_config(&[entry]);
    assert!(
        result.is_err(),
        "from_config with a nonexistent cert_path must return Err"
    );
}

// ---------------------------------------------------------------------------
// Test 10: store configured with the UNTRUSTED CA rejects the trusted CA's
// leaf cert, and does NOT authenticate alice.
//
// Security invariant: configuring a different CA does not grant cross-CA
// authentication.  This test uses UNTRUSTED_CA_CERT_DER loaded as the sole
// trusted issuer.
// ---------------------------------------------------------------------------

#[test]
fn store_with_wrong_ca_cert_path_rejects_trusted_ca_leaf() {
    let (tmp, path) = ca_der_to_pem_file(UNTRUSTED_CA_CERT_DER);
    let entry = TrustedIssuerEntry {
        cert_path: path.to_string_lossy().into_owned(),
    };
    let store = TrustedIssuerStore::from_config(&[entry])
        .expect("from_config with untrusted CA cert must succeed");
    drop(tmp);

    // alice's cert is signed by the TRUSTED CA, not the untrusted CA.
    let result = store.verify_and_extract_cn(LEAF_ALICE_DER);
    assert!(
        result.is_ok(),
        "verify_and_extract_cn must not error: {:?}",
        result.err()
    );
    assert_eq!(
        result.unwrap(),
        None,
        "cert signed by the trusted CA must be rejected when only the untrusted CA is configured"
    );
}
